[Serializable]
public class Permission
{
    public string Name { get; set; }
    public string Resource { get; set; }
    public PermissionLevel Level { get; set; }
    public DateTime GrantedAt { get; set; }
    public DateTime? ExpiresAt { get; set; }

    public Permission(string name, string resource, PermissionLevel level)
    {
        Name = name;
        Resource = resource;
        Level = level;
        GrantedAt = DateTime.UtcNow;
    }

    public bool IsExpired()
    {
        return ExpiresAt.HasValue && DateTime.UtcNow > ExpiresAt.Value;
    }

    public bool CanRead()
    {
        return !IsExpired() && (Level == PermissionLevel.Read || Level == PermissionLevel.ReadWrite || Level == PermissionLevel.Admin);
    }

    public bool CanWrite()
    {
        return !IsExpired() && (Level == PermissionLevel.ReadWrite || Level == PermissionLevel.Admin);
    }

    public bool CanAdmin()
    {
        return !IsExpired() && Level == PermissionLevel.Admin;
    }

    public Permission Elevate(PermissionLevel newLevel)
    {
        if (newLevel <= Level)
            throw new InvalidOperationException("Cannot elevate to a lower or equal permission level.");
        return new Permission(Name, Resource, newLevel)
        {
            GrantedAt = this.GrantedAt,
            ExpiresAt = this.ExpiresAt
        };
    }

    public override string ToString()
    {
        return $"Permission[{Name}] on {Resource} ({Level}) - Expired: {IsExpired()}";
    }
}

[Serializable]
public enum PermissionLevel
{
    None = 0,
    Read = 1,
    ReadWrite = 2,
    Admin = 3
}

