[Serializable]
public class ShoppingCart
{
    public List<CartItem> Items { get; set; } = new List<CartItem>();
    public DateTime LastModified { get; set; }

    public void AddItem(CartItem item)
    {
        var existing = Items.Find(i => i.ProductId == item.ProductId);
        if (existing != null)
        {
            existing.Quantity += item.Quantity;
        }
        else
        {
            Items.Add(item);
        }
        LastModified = DateTime.UtcNow;
    }

    public bool RemoveItem(string productId)
    {
        var removed = Items.RemoveAll(i => i.ProductId == productId) > 0;
        if (removed) LastModified = DateTime.UtcNow;
        return removed;
    }

    public void UpdateQuantity(string productId, int quantity)
    {
        var item = Items.Find(i => i.ProductId == productId);
        if (item == null)
            throw new InvalidOperationException($"Product {productId} not found in cart.");
        if (quantity <= 0)
        {
            RemoveItem(productId);
        }
        else
        {
            item.Quantity = quantity;
            LastModified = DateTime.UtcNow;
        }
    }

    public decimal GetCartTotal()
    {
        decimal total = 0;
        foreach (var item in Items)
            total += item.GetTotal();
        return total;
    }

    public void Clear()
    {
        Items.Clear();
        LastModified = DateTime.UtcNow;
    }

    public int GetItemCount()
    {
        int count = 0;
        foreach (var item in Items)
            count += item.Quantity;
        return count;
    }
}

