    public UserSession()
    {
        SessionId = Guid.NewGuid().ToString("N");
        Preferences = new UserPreferences();
        Cart = new ShoppingCart();
        Permissions = new List<Permission>();
        Metadata = new Dictionary<string, object>();
        CreatedAt = DateTime.UtcNow;
        LastAccessedAt = DateTime.UtcNow;
    }

    public UserSession(string userId, string username, string email, TimeSpan? sessionDuration = null)
        : this()
    {
        UserId = userId;
        Username = username;
        Email = email;
        if (sessionDuration.HasValue)
            ExpiresAt = DateTime.UtcNow.Add(sessionDuration.Value);
    }

    public bool IsExpired()
    {
        return ExpiresAt.HasValue && DateTime.UtcNow > ExpiresAt.Value;
    }

    public void Touch()
    {
        LastAccessedAt = DateTime.UtcNow;
    }

    public void AddPermission(Permission permission)
    {
        var existing = Permissions.Find(p => p.Name == permission.Name && p.Resource == permission.Resource);
        if (existing != null)
            Permissions.Remove(existing);
        Permissions.Add(permission);
    }

    public bool HasPermission(string resource, PermissionLevel requiredLevel)
    {
        foreach (var p in Permissions)
        {
            if (p.Resource == resource && !p.IsExpired() && p.Level >= requiredLevel)
                return true;
        }
        return false;
    }

    public Permission GetPermission(string resource)
    {
        return Permissions.Find(p => p.Resource == resource && !p.IsExpired());
    }

    public void RevokePermission(string name, string resource)
    {
        Permissions.RemoveAll(p => p.Name == name && p.Resource == resource);
    }

    public void SetMetadata(string key, object value)
    {
        Metadata[key] = value;
    }

    public object GetMetadata(string key)
    {
        return Metadata.ContainsKey(key) ? Metadata[key] : null;
    }
}

public class SessionManager
{
    private readonly string _sessionDirectory;
    private readonly Dictionary<string, UserSession> _activeSessions;
    private readonly object _lock = new object();
    private readonly TimeSpan _defaultSessionDuration;

    public SessionManager(string sessionDirectory = null, TimeSpan? defaultSessionDuration = null)
    {
        _sessionDirectory = sessionDirectory ?? Path.Combine(Path.GetTempPath(), "sessions");
        _defaultSessionDuration = defaultSessionDuration ?? TimeSpan.FromHours(24);
        _activeSessions = new Dictionary<string, UserSession>();

        if (!Directory.Exists(_sessionDirectory))
            Directory.CreateDirectory(_sessionDirectory);
    }

    public UserSession CreateSession(string userId, string username, string email, TimeSpan? duration = null)
    {
        lock (_lock)
        {
            var session = new UserSession(userId, username, email, duration ?? _defaultSessionDuration);
            _activeSessions[session.SessionId] = session;
            SaveSessionToDisk(session);
            Console.WriteLine($"Session created: {session.SessionId} for user {username}");
            return session;
        }
    }

    public UserSession GetSession(string sessionId)
    {
        lock (_lock)
        {
            if (_activeSessions.TryGetValue(sessionId, out var session))
            {
                if (session.IsExpired())
                {
                    Console.WriteLine($"Session {sessionId} has expired. Removing.");
                    DestroySession(sessionId);
                    return null;
                }
                session.Touch();
                return session;
            }

            session = LoadSessionFromDisk(sessionId);
            if (session != null)
            {
                if (session.IsExpired())
                {
                    Console.WriteLine($"Session {sessionId} loaded from disk but expired. Removing.");
                    DestroySession(sessionId);
                    return null;
                }
                session.Touch();
                _activeSessions[sessionId] = session;
            }
            return session;
        }
    }

    public void SaveSession(string sessionId)
    {
        lock (_lock)
        {
            if (_activeSessions.TryGetValue(sessionId, out var session))
            {
                SaveSessionToDisk(session);
            }
        }
    }

    public void SaveAllSessions()
    {
        lock (_lock)
        {
            foreach (var kvp in _activeSessions)
            {
                SaveSessionToDisk(kvp.Value);
            }
            Console.WriteLine($"Saved {_activeSessions.Count} sessions to disk.");
        }
    }

    public bool DestroySession(string sessionId)
    {
        lock (_lock)
        {
            _activeSessions.Remove(sessionId);
            var filePath = GetSessionFilePath(sessionId);
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
                Console.WriteLine($"Session {sessionId} destroyed and removed from disk.");
                return true;
            }
            return false;
        }
    }

    public int CleanExpiredSessions()
    {
        lock (_lock)
        {
            int cleaned = 0;
            var expiredKeys = new List<string>();

            foreach (var kvp in _activeSessions)
            {
                if (kvp.Value.IsExpired())
                    expiredKeys.Add(kvp.Key);
            }

            foreach (var key in expiredKeys)
            {
                DestroySession(key);
                cleaned++;
            }

            // Also check disk
            if (Directory.Exists(_sessionDirectory))
            {
                foreach (var file in Directory.GetFiles(_sessionDirectory, "*.session"))
                {
                    var sessionId = Path.GetFileNameWithoutExtension(file);
                    if (!_activeSessions.ContainsKey(sessionId))
                    {
                        var session = LoadSessionFromDisk(sessionId);
                        if (session != null && session.IsExpired())
                        {
                            File.Delete(file);
                            cleaned++;
                        }
                    }
                }
            }

            Console.WriteLine($"Cleaned {cleaned} expired sessions.");
            return cleaned;
        }
    }

    public List<string> GetActiveSessionIds()
    {
        lock (_lock)
        {
            return new List<string>(_activeSessions.Keys);
        }
    }

    public UserSession GetSessionByUserId(string userId)
    {
        lock (_lock)
        {
            foreach (var kvp in _activeSessions)
            {
                if (kvp.Value.UserId == userId && !kvp.Value.IsExpired())
                    return kvp.Value;
            }
            return null;
        }
    }

    #pragma warning disable SYSLIB0011
    private void SaveSessionToDisk(UserSession session)
    {
        var filePath = GetSessionFilePath(session.SessionId);
        try
        {
            using (var stream = new FileStream(filePath, FileMode.Create, FileAccess.Write))
            {
                var formatter = new BinaryFormatter();
                formatter.Serialize(stream, session);
            }
        }
        catch (SerializationException ex)
        {
            Console.WriteLine($"Error serializing session {session.SessionId}: {ex.Message}");
        }
        catch (IOException ex)
        {
            Console.WriteLine($"Error writing session file {filePath}: {ex.Message}");
        }
    }

    private UserSession LoadSessionFromDisk(string sessionId)
    {
        var filePath = GetSessionFilePath(sessionId);
        if (!File.Exists(filePath))
            return null;

        try
        {
            using (var stream = new FileStream(filePath, FileMode.Open, FileAccess.Read))
            {
                var formatter = new BinaryFormatter();
                return (UserSession)formatter.Deserialize(stream);
            }
        }
        catch (SerializationException ex)
        {
            Console.WriteLine($"Error deserializing session {sessionId}: {ex.Message}");
            return null;
        }
        catch (IOException ex)
        {
            Console.WriteLine($"Error reading session file {filePath}: {ex.Message}");
            return null;
        }
    }
    #pragma warning restore SYSLIB0011

    private string GetSessionFilePath(string sessionId)
    {
        // Sanitize session ID to prevent path traversal
        var sanitized = sessionId.Replace(Path.DirectorySeparatorChar, '_')
                                  .Replace(Path.AltDirectorySeparatorChar, '_')
                                  .Replace("..", "_");
        return Path.Combine(_sessionDirectory, sanitized + ".session");
    }
}

public class Program
{
    public static void Main(string[] args)
    {
        Console.WriteLine("=== Session Management System Demo ===\n");

        var sessionDir = Path.Combine(Path.GetTempPath(), "demo_sessions_" + Guid.NewGuid().ToString("N"));
        var manager = new SessionManager(sessionDir, TimeSpan.FromHours(2));

        try
        {
            // Create a session
            var session = manager.CreateSession("user123", "john_doe", "john@example.com");
            Console.WriteLine($"Created session: {session.SessionId}");
            Console.WriteLine($"User: {session.Username}, Email: {session.Email}");
            Console.WriteLine($"Expires at: {session.ExpiresAt}\n");

            // Set preferences
            session.Preferences.Theme = "dark";
            session.Preferences.Language = "en";
            session.Preferences.Currency = "EUR";
            session.Preferences.ItemsPerPage = 50;
            session.Preferences.SetCustomSetting("sidebar_collapsed", "true");
            session.Preferences.SetCustomSetting("font_size", "14");
            Console.WriteLine($"Preferences set - Theme: {session.Preferences.Theme}, Language: {session.Preferences.Language}");
            Console.WriteLine($"Custom setting 'font_size': {session.Preferences.GetCustomSetting("font_size")}\n");

            // Add items to cart
            session.Cart.AddItem(new CartItem("PROD001", "Wireless Mouse", 29.99m, 1));
            session.Cart.AddItem(new CartItem("PROD002", "USB-C Hub", 49.99m, 2));
            session.Cart.AddItem(new CartItem("PROD003", "Mechanical Keyboard", 129.99m, 1));
            Console.WriteLine("Shopping Cart:");
            foreach (var item in session.Cart.Items)
                Console.WriteLine($"  {item}");
            Console.WriteLine($"Cart Total: ${session.Cart.GetCartTotal():F2}");
            Console.WriteLine($"Item Count: {session.Cart.GetItemCount()}\n");

            // Update cart
            session.Cart.UpdateQuantity("PROD002", 3);
            session.Cart.RemoveItem("PROD001");
            Console.WriteLine("After updating cart:");
            foreach (var item in session.Cart.Items)
                Console.WriteLine($"  {item}");
            Console.WriteLine($"Cart Total: ${session.Cart.GetCartTotal():F2}\n");

            // Add permissions
            session.AddPermission(new Permission("read_products", "/api/products", PermissionLevel.Read));
            session.AddPermission(new Permission("manage_orders", "/api/orders", PermissionLevel.ReadWrite));
            session.AddPermission(new Permission("admin_users", "/api/users", PermissionLevel.Admin));

            var expiredPerm = new Permission("temp_access", "/api/reports", PermissionLevel.Read)
            {
                ExpiresAt = DateTime.UtcNow.AddSeconds(-1) // Already expired
            };
            session.AddPermission(expiredPerm);

            Console.WriteLine("Permissions:");
            foreach (var perm in session.Permissions)
                Console.WriteLine($"  {perm}");

            Console.WriteLine($"\nHas Read on /api/products: {session.HasPermission("/api/products", PermissionLevel.Read)}");
            Console.WriteLine($"Has Write on /api/products: {session.HasPermission("/api/products", PermissionLevel.ReadWrite)}");
            Console.WriteLine($"Has Write on /api/orders: {session.HasPermission("/api/orders", PermissionLevel.ReadWrite)}");
            Console.WriteLine($"Has Admin on /api/users: {session.HasPermission("/api/users", PermissionLevel.Admin)}");
            Console.WriteLine($"Has Read on /api/reports (expired): {session.HasPermission("/api/reports", PermissionLevel.Read)}");

            var orderPerm = session.GetPermission("/api/orders");
            Console.WriteLine($"\nOrder permission - CanRead: {orderPerm.CanRead()}, CanWrite: {orderPerm.CanWrite()}, CanAdmin: {orderPerm.CanAdmin()}");

            // Set metadata
            session.SetMetadata("ip_address", "192.168.1.100");
            session.SetMetadata("user_agent", "Mozilla/5.0");
            session.SetMetadata("login_count", 42);
            Console.WriteLine($"\nMetadata - IP: {session.GetMetadata("ip_address")}, Login Count: {session.GetMetadata("login_count")}\n");

            // Save session to disk
            manager.SaveSession(session.SessionId);
            Console.WriteLine("Session saved to disk.\n");

            // Simulate loading from disk by creating a new manager
            var manager2 = new SessionManager(sessionDir);
            var loadedSession = manager2.GetSession(session.SessionId);

            if (loadedSession != null)
            {
                Console.WriteLine("=== Session Loaded from Disk ===");
                Console.WriteLine($"Session ID: {loadedSession.SessionId}");
                Console.WriteLine($"User: {loadedSession.Username} ({loadedSession.UserId})");
                Console.WriteLine($"Email: {loadedSession.Email}");
                Console.WriteLine($"Theme: {loadedSession.Preferences.Theme}");
                Console.WriteLine($"Cart Items: {loadedSession.Cart.Items.Count}, Total: ${loadedSession.Cart.GetCartTotal():F2}");
                Console.WriteLine($"Permissions: {loadedSession.Permissions.Count}");
                Console.WriteLine($"Has Admin on /api/users: {loadedSession.HasPermission("/api/users", PermissionLevel.Admin)}");
                Console.WriteLine($"Metadata IP: {loadedSession.GetMetadata("ip_address")}");
                Console.WriteLine($"Created: {loadedSession.CreatedAt}");
                Console.WriteLine($"Last Accessed: {loadedSession.LastAccessedAt}");
            }

            // Create another session and test multiple sessions
            Console.WriteLine("\n=== Multiple Sessions Test ===");
            var session2 = manager.CreateSession("user456", "jane_smith", "jane@example.com");
            session2.Cart.AddItem(new CartItem("PROD010", "Laptop Stand", 79.99m, 1));
            session2.AddPermission(new Permission("read_all", "/api/*", PermissionLevel.Read));
            manager.SaveSession(session2.SessionId);

            Console.WriteLine($"Active sessions: {manager.GetActiveSessionIds().Count}");

            // Test permission elevation
            Console.WriteLine("\n=== Permission Elevation Test ===");
            var readPerm = new Permission("access", "/api/data", PermissionLevel.Read);
            Console.WriteLine($"Original: {readPerm}");
            var elevatedPerm = readPerm.Elevate(PermissionLevel.Admin);
            Console.WriteLine($"Elevated: {elevatedPerm}");

            // Test session expiry
            Console.WriteLine("\n=== Session Expiry Test ===");
            var shortSession = manager.CreateSession("user789", "temp_user", "temp@example.com", TimeSpan.FromMilliseconds(1));
            System.Threading.Thread.Sleep(10);
            var retrieved = manager.GetSession(shortSession.SessionId);
            Console.WriteLine($"Expired session retrieved: {(retrieved == null ? "null (correctly expired)" : "still active")}");

            // Clean up expired sessions
            int cleaned = manager.CleanExpiredSessions();
            Console.WriteLine($"Cleaned expired sessions: {cleaned}");

            // Destroy a session
            Console.WriteLine("\n=== Session Destruction ===");
            manager.DestroySession(session2.SessionId);
            Console.WriteLine($"Active sessions after destruction: {manager.GetActiveSessionIds().Count}");

            // Save remaining
            manager.SaveAllSessions();
        }
        finally
        {
            // Clean up demo directory
            if (Directory.Exists(sessionDir))
            {
                try
                {
                    Directory.Delete(sessionDir, true);
                    Console.WriteLine($"\nCleaned up demo session directory: {sessionDir}");
                }
                catch { }
            }
        }

        Console.WriteLine("\n=== Demo Complete ===");
    }
}